* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: Arial, sans-serif;
}

body {
    background: #f5f7fa;
    color: #333;
}

/* Navbar */
header {
    background: #0f172a;
    padding: 15px 8%;
    position: sticky;
    top: 0;
    z-index: 1000;
}

.navbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.logo {
    color: white;
    font-size: 24px;
    font-weight: bold;
}

.nav-links {
    display: flex;
    list-style: none;
}

.nav-links li {
    margin-left: 25px;
}

.nav-links a {
    color: white;
    text-decoration: none;
    transition: 0.3s;
}

.nav-links a:hover {
    color: #38bdf8;
}

.menu-toggle {
    display: none;
    font-size: 28px;
    color: white;
    cursor: pointer;
}

/* Hero */
.hero {
    height: 100vh;
    background: linear-gradient(rgba(0, 0, 0, 0.5), rgba(0, 0, 0, 0.5)),
        url('https://images.unsplash.com/photo-1497366754035-f200968a6e72?q=80&w=1200&auto=format&fit=crop') center/cover;

    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    color: white;
    padding: 20px;
}

.hero-content {
    max-width: 700px;
}

.hero h1 {
    font-size: 52px;
    margin-bottom: 20px;
}

.hero p {
    margin-bottom: 25px;
    line-height: 1.7;
}

.hero button {
    padding: 12px 25px;
    border: none;
    background: #38bdf8;
    color: white;
    font-size: 16px;
    cursor: pointer;
    border-radius: 6px;
    transition: 0.3s;
}

.hero button:hover {
    background: #0ea5e9;
}

/* Section */
section {
    padding: 80px 8%;
}

section h2 {
    text-align: center;
    margin-bottom: 50px;
    font-size: 36px;
}

/* About */
.about-container {
    display: flex;
    gap: 40px;
    align-items: center;
    flex-wrap: wrap;
}

.about-text {
    flex: 1;
}

.about-text p {
    margin-bottom: 20px;
    line-height: 1.8;
}

.about-image {
    flex: 1;
}

.about-image img {
    width: 100%;
    border-radius: 12px;
}

/* Services */
.service-boxes {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 25px;
}

.service-card {
    background: white;
    padding: 30px;
    border-radius: 12px;
    text-align: center;
    transition: 0.3s;
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.08);
}

.service-card:hover {
    transform: translateY(-10px);
}

.service-card h3 {
    margin-bottom: 15px;
}

/* Team */
.team-container {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 25px;
}

.team-card {
    background: white;
    padding: 25px;
    text-align: center;
    border-radius: 12px;
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.08);
}

.team-card img {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    margin-bottom: 15px;
}

/* Contact */
.contact-form {
    max-width: 600px;
    margin: auto;
    display: flex;
    flex-direction: column;
}

.contact-form input,
.contact-form textarea {
    margin-bottom: 20px;
    padding: 15px;
    border: 1px solid #ccc;
    border-radius: 8px;
}

.contact-form textarea {
    height: 150px;
    resize: none;
}

.contact-form button {
    padding: 14px;
    border: none;
    background: #0f172a;
    color: white;
    border-radius: 8px;
    cursor: pointer;
}

.contact-form button:hover {
    background: #1e293b;
}

/* Footer */
footer {
    background: #0f172a;
    color: white;
    text-align: center;
    padding: 20px;
}

/* Responsive */
@media(max-width: 768px) {

    .nav-links {
        position: absolute;
        top: 70px;
        right: 0;
        background: #0f172a;
        width: 220px;
        flex-direction: column;
        display: none;
        padding: 20px;
    }

    .nav-links.active {
        display: flex;
    }

    .nav-links li {
        margin: 15px 0;
    }

    .menu-toggle {
        display: block;
    }

    .hero h1 {
        font-size: 38px;
    }
}
